import React, { createContext, useState, useContext } from 'react';
import axiosInstance from '../axiosConfig';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(() => {
    // ✅ Persist user across page refresh
    const stored = localStorage.getItem('user');
    return stored ? JSON.parse(stored) : null;
  });

  const login = (userData) => {
    // ✅ Save ALL user fields including profilePicture
    setUser(userData);
    localStorage.setItem('user', JSON.stringify(userData));
    // ✅ Set token for all future axios requests
    if (userData.token) {
      axiosInstance.defaults.headers.common['Authorization'] = `Bearer ${userData.token}`;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
    delete axiosInstance.defaults.headers.common['Authorization'];
  };

  // ✅ Re-attach token on app reload
  if (user?.token) {
    axiosInstance.defaults.headers.common['Authorization'] = `Bearer ${user.token}`;
  }

  return (
    <AuthContext.Provider value={{ user, login, logout, setUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
